#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, K, S; scanf("%lld %lld %lld", &N, &K, &S);
        long long x = (S - N*N) / (K - 1);
        printf("%lld\n", x);
    }
    return 0;
}

